import{_ as i,o as e,c as s,ao as n}from"./chunks/framework.B6CCY6RT.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"manual/intro.md","filePath":"manual/intro.md","lastUpdated":null}'),t={name:"manual/intro.md"};function o(l,a,p,r,c,d){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="Introduction" tabindex="-1">Introduction <a class="header-anchor" href="#Introduction" aria-label="Permalink to &quot;Introduction {#Introduction}&quot;">​</a></h1><p>A vine copula decomposes a multivariate copula density into a product of bivariate pair-copula densities evaluated at recursively computed conditional distribution values. <code>VineCopulas.jl</code> implements this construction in native Julia and delegates the underlying pair-copula families to <code>Copulas.jl</code>.</p><p>The package is organized around explicit model objects:</p><ul><li><p><a href="/VineCopulas.jl/v0.1/api/public#VineCopulas.CVineCopula"><code>CVineCopula</code></a> for canonical vines with one root variable per tree;</p></li><li><p><a href="/VineCopulas.jl/v0.1/api/public#VineCopulas.DVineCopula"><code>DVineCopula</code></a> for drawable/path-like vines;</p></li><li><p><a href="/VineCopulas.jl/v0.1/api/public#VineCopulas.RVineCopula"><code>RVineCopula</code></a> for regular-vine structures represented through structure arrays and matrix exchange helpers.</p></li></ul><p>All vine objects are subtypes of <a href="/VineCopulas.jl/v0.1/api/public#VineCopulas.AbstractVineCopula"><code>AbstractVineCopula</code></a>, which itself is a subtype of <code>Copulas.Copula</code>.</p><h2 id="Relationship-with-Copulas.jl" tabindex="-1">Relationship with Copulas.jl <a class="header-anchor" href="#Relationship-with-Copulas.jl" aria-label="Permalink to &quot;Relationship with Copulas.jl {#Relationship-with-Copulas.jl}&quot;">​</a></h2><p><code>Copulas.jl</code> provides the bivariate copula families. <code>VineCopulas.jl</code> supplies the conditional primitives and the recursive vine composition layer.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Copulas.jl</span></span>
<span class="line"><span>└── bivariate copula families</span></span>
<span class="line"><span>    └── VineCopulas.jl</span></span>
<span class="line"><span>        ├── C-vines</span></span>
<span class="line"><span>        ├── D-vines</span></span>
<span class="line"><span>        └── R-vines</span></span></code></pre></div><p>This means the mathematical definition and parameters of individual pair-copulas remain those of <code>Copulas.jl</code>, while the vine structure, pair-copula placement, Rosenblatt transforms, and conditional recursion are handled here.</p><h2 id="Data-orientation" tabindex="-1">Data orientation <a class="header-anchor" href="#Data-orientation" aria-label="Permalink to &quot;Data orientation {#Data-orientation}&quot;">​</a></h2><p>Matrices are interpreted as <code>p × n</code>: rows are dimensions and columns are observations. A single point is a vector of length <code>p</code>.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">U </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> rand</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rng, vine, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># p × 100</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">logpdf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(vine, U)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># vector of length 100</span></span></code></pre></div>`,12)])])}const C=i(t,[["render",o]]);export{h as __pageData,C as default};
